mapper.select:
SELECT im.* , t.NODE_NM , p.NODE_NM AS PARENT_NM FROM TW_IMPROVE im LEFT JOIN TW_EVAL_DTL ed ON im.DTL_ID = ed.DTL_ID LEFT JOIN TW_TREE t ON ed.NODE_ID = t.NODE_ID LEFT JOIN TW_TREE p ON t.PARENT_ID = p.NODE_ID
AND im.IMP_STATUS = #{impStatus}
ORDER BY im.IMPROVE_ID DESC

mapper.update:
UPDATE TW_IMPROVE
   SET TITLE = #{title}
     , CONTENT = #{content}
     , IMP_STATUS = #{impStatus}
     , DUE_DT = #{dueDt}
     , COMP_DT = #{compDt}
     , MANAGER = #{manager}
 WHERE IMPROVE_ID = #{improveId}
